mpt_snapshots/agent.txt` and `cli/internal/agent/testdata/execute_bead_prompt_snapshots/claude.txt` match the updated prompt source.\\n4. `cd cli \\u0026\\u0026 go test ./internal/agent/... -run 'TestExecuteBeadPromptSnapshots|TestExecuteBeadPromptSnapshotsUseParentToChildDecompositionEdges' -count=1` passes.\\n5. `lefthook run pre-commit` passes.\\nCreated:  2026-06-17 19:58:50\\nUpdated:  2026-06-17 19:58:50\\nspec-id: FEAT-010\\n\"}}\n.ddx/executions/20260617T195546-6fe14552/embedded/agent-codex-1781726166441906314.jsonl:60:{\"type\":\"tool_call\",\"sequence\":59,\"time\":\"2026-06-17T20:00:18.686617763Z\",\"metadata\":{\"DDX_ATTEMPT_ID\":\"20260617T195546-6fe14552\",\"DDX_BEAD_DIR\":\"/Users/erik/Projects/ddx/.ddx\",\"DDX_BEAD_ID\":\"ddx-e9542e0d\",\"DDX_MODE\":\"bead_execution\",\"GIT_CONFIG_GLOBAL\":\"/Users/erik/Projects/.ddx-exec-wt/.execute-bead-wt-ddx-e9542e0d-20260617T195546-6fe14552/.ddx/executions/20260617T195546-6fe14552/embedded/git-global.cfg\",\"GIT_CONFIG_SYSTEM\":\"/dev/null\",\"PATH\":\"/Users/erik/Projects/.ddx-exec-wt/.execute-bead-wt-ddx-e9542e0d-20260617T195546-6fe14552/.ddx/executions/20260617T195546-6fe14552/embedded/git-bin:/home/erik/.local/bin:/home/erik/.local/share/mise/shims:/home/erik/bin:/home/linuxbrew/.linuxbrew/bin:/home/linuxbrew/.linuxbrew/sbin:/home/erik/.codex/tmp/arg0/codex-arg0Yu4YDA:/usr/local/cuda/bin:/home/erik/.jbang/bin:/home/erik/.opencode/bin:/Users/erik/.antigravity/antigravity/bin:/home/erik/.dotfiles/git-subrepo/lib:/Applications/SnowSQL.app/Contents/MacOS:/home/erik/.local/share/coursier/bin:/home/erik/.dotfiles/git-fuzzy/bin:/home/erik/go/bin:/home/erik/.dotfiles/scripts:/home/erik/.cargo/bin:/usr/local/sbin:/usr/local/bin:/usr/sbin:/usr/bin:/sbin:/bin:/usr/games:/usr/local/games:/snap/bin:/Users/erik/Library/Application Support/JetBrains/Toolbox/scripts:/Users/erik/Library/Application Support/Coursier/bin:/home/erik/.lmstudio/bin:/home/erik/.cache/lm-studio/bin:/Users/erik/.cache/lm-studio/bin:/Users/erik/.lmst